from typing import Any, Callable, Dict, List, Tuple



class ContextWindowMixin:
    async def _ask_compress_now(
        self, event_call: Callable, history_tokens: int, budget: int
    ) -> bool:
        """Blocks (via the client websocket) until the user answers a Yes/Cancel
        confirmation dialog, or times out. Any non-`True` result (decline,
        timeout, disconnected session) is treated as "don't compress yet"."""
        percent_used = int(history_tokens / budget * 100) if budget else 100
        try:
            result = await event_call(
                {
                    "type": "confirmation",
                    "data": {
                        "title": "Context usage warning",
                        "message": (
                            f"Conversation history is at {history_tokens:,} tokens "
                            f"({percent_used}% of your {budget:,}-token budget). Compress "
                            "older messages now to free up space, or continue as-is?"
                        ),
                    },
                }
            )
        except Exception as e:
            self.debug_log(1, f"Warning-threshold confirmation call failed: {e}", "⚠️")
            return False
        return result is True

    async def build_context_window(
        self,
        history_messages: List[dict],
        budget: int,
        anchor_n: int,
        recent_n: int,
        covered_upto: int,
        blocks: List[Dict[str, str]],
        force: bool = False,
        preserve_latest_unit: bool = True,
    ) -> Tuple[List[dict], int, List[Dict[str, str]], Dict[str, Any]]:
        """Assemble anchor + persisted summary blocks + verbatim "pending" middle +
        recent messages, and compare THAT candidate to budget - not the raw
        history size, which never shrinks and would re-trigger this on every turn.

        Only when the candidate still doesn't fit do we fold all of `pending`
        into one new, permanently-frozen summary block. Blocks are generated
        exactly once and never re-summarized, so a long conversation accumulates
        a short, append-only list of summaries instead of repeatedly
        re-summarizing (and degrading) the same content.

        `force=True` folds `pending` immediately regardless of whether the
        candidate fits the budget - used when the user opts to compress early
        via the warning-threshold prompt, ahead of the hard cap.

        NOTE: `blocks` is intentionally left unbounded here - it is never capped
        or merged. For a pathologically long-lived chat (many fold events) this
        list would itself keep growing the token cost of the "blocks" section.
        Deferred for now per explicit decision; revisit with e.g. a
        max-block-count valve that merges the oldest two blocks if this ever
        becomes a real problem in practice.
        """
        n = len(history_messages)
        if n == 0:
            return (
                [],
                covered_upto,
                blocks,
                {
                    "kept": 0,
                    "summarized_count": 0,
                    "block_count": len(blocks),
                    "folded": False,
                },
            )

        effective_recent_n = recent_n
        if force:
            units = atomic_message_units(history_messages)
            effective_recent_n = (
                n - units[-1][0] if preserve_latest_unit and units else 0
            )

        anchor_n, recent_start = tool_safe_window_boundaries(
            history_messages,
            anchor_count=anchor_n,
            recent_count=effective_recent_n,
        )
        covered_upto = max(anchor_n, min(covered_upto, recent_start))
        covered_upto = max(
            anchor_n,
            tool_safe_window_boundaries(
                history_messages,
                anchor_count=covered_upto,
                recent_count=n - recent_start,
            )[0],
        )

        anchor = history_messages[:anchor_n]
        pending = history_messages[covered_upto:recent_start]
        recent = history_messages[recent_start:]

        def block_messages(block_list: List[Dict[str, str]]) -> List[dict]:
            return [
                {
                    "role": "system",
                    "content": f"[Summary of earlier conversation]\n{b['text']}",
                }
                for b in block_list
            ]

        candidate = anchor + block_messages(blocks) + pending + recent
        folded = False
        over_budget = self.count_messages_tokens(candidate) > budget

        if self.valves.enable_overflow_summary and (force or over_budget):
            # Old state can contain one map summary per former 24K chunk. Merge
            # those blocks first so persisted summaries cannot dominate context.
            existing_block_messages = block_messages(blocks)
            if existing_block_messages and (
                len(blocks) > 1
                or self.count_messages_tokens(existing_block_messages)
                > int(self.valves.summary_max_tokens)
            ):
                base_tokens = self.count_messages_tokens(anchor + pending + recent)
                block_target = max(
                    64,
                    min(
                        int(self.valves.summary_max_tokens),
                        max(64, budget - base_tokens),
                    ),
                )
                merged = await self.generate_overflow_summary(
                    existing_block_messages,
                    target_tokens=block_target,
                )
                if merged:
                    blocks = [{"text": merged}]
                    folded = True

            excluded = list(pending)
            fold_end = recent_start
            remaining_recent = list(recent)

            # Recent-message retention is a preference, not a hard guarantee.
            # Move the oldest complete recent exchanges into this fold until a
            # bounded summary plus the remaining request can fit. Always retain
            # the newest atomic exchange for the provider continuation.
            units = atomic_message_units(remaining_recent)
            minimum_units = 1 if preserve_latest_unit else 0
            while len(units) > minimum_units:
                base = anchor + block_messages(blocks) + remaining_recent
                projected = self.count_messages_tokens(base) + int(
                    self.valves.summary_max_tokens
                )
                if projected <= budget:
                    break
                start, end = units[0]
                excluded.extend(remaining_recent[start:end])
                fold_end += end - start
                remaining_recent = remaining_recent[end:]
                units = atomic_message_units(remaining_recent)

            if excluded:
                base_tokens = self.count_messages_tokens(
                    anchor + block_messages(blocks) + remaining_recent
                )
                summary_target = max(
                    64,
                    min(
                        int(self.valves.summary_max_tokens),
                        max(64, budget - base_tokens),
                    ),
                )
                summary_text = await self.generate_overflow_summary(
                    excluded,
                    target_tokens=summary_target,
                )
                if summary_text:
                    blocks = blocks + [{"text": summary_text}]
                    covered_upto = fold_end
                    folded = True
                    pending = []
                    recent = remaining_recent

            candidate = anchor + block_messages(blocks) + pending + recent

        stats = {
            "kept": len(anchor) + len(pending) + len(recent),
            "summarized_count": covered_upto - anchor_n,
            "block_count": len(blocks),
            "folded": folded,
        }
        return candidate, covered_upto, blocks, stats

# === owui_manifolds/filters/context.py ===
import json
import traceback
from typing import Any, Callable, Dict, List, Optional



class ContextManager(
    ContextModelingMixin,
    ContextTokenMixin,
    ContextSummaryMixin,
    ContextToolCompactionMixin,
    ContextPersistenceMixin,
    ContextWindowMixin,
):
    Valves = ContextValves
    UserValves = ContextUserValves

    def __init__(self):
        self.valves = self.Valves()
        self.model_matcher = ModelMatcher()
        self.token_calculator = TokenCalculator()
        self._current_model_name = ""
        self._current_model_info: Dict[str, Any] = {}
        self._summary_calls_used = 0

    def debug_log(self, level: int, message: str, emoji: str = "🔧"):
        if self.valves.debug_level >= level:
            print(f"{emoji} {message}")

    async def inlet(
        self,
        body: dict,
        user: Optional[dict] = None,
        __event_emitter__: Optional[Callable] = None,
        __event_call__: Optional[Callable] = None,
        __user__: Optional[dict] = None,
        __model__: Optional[dict] = None,
        __chat_id__: Optional[str] = None,
        **kwargs,
    ) -> dict:
        if context_is_prepared(body):
            return body
        processed = await self._process_body(
            body,
            user=user,
            __event_emitter__=__event_emitter__,
            __event_call__=__event_call__,
            __user__=__user__,
            __model__=__model__,
            __chat_id__=__chat_id__,
            **kwargs,
        )
        return mark_context_prepared(processed)

    async def _process_body(
        self,
        body: dict,
        user: Optional[dict] = None,
        __event_emitter__: Optional[Callable] = None,
        __event_call__: Optional[Callable] = None,
        __user__: Optional[dict] = None,
        __model__: Optional[dict] = None,
        __chat_id__: Optional[str] = None,
        **kwargs,
    ) -> dict:
        if not self.valves.enable_processing:
            return body

        messages = body.get("messages", [])
        if not messages:
            return body

        self._summary_calls_used = 0
        messages, legacy_details_removed = strip_legacy_details_from_messages(messages)
        body["messages"] = messages

        model_name = body.get("model", "unknown")
        base_model_id = isinstance(__model__, dict) and __model__.get("info", {}).get(
            "base_model_id"
        )
        if base_model_id:
            model_name = base_model_id
        if self.is_model_excluded(model_name):
            return body

        self._current_model_name = model_name

        user_dict = (
            user
            if isinstance(user, dict)
            else (__user__ if isinstance(__user__, dict) else None)
        )
        user_valves = None
        if isinstance(user_dict, dict):
            raw_uv = user_dict.get("valves")
            if isinstance(raw_uv, self.UserValves):
                user_valves = raw_uv
            elif isinstance(raw_uv, dict):
                try:
                    user_valves = self.UserValves(**raw_uv)
                except Exception:
                    user_valves = None
        if user_valves is None:
            user_valves = self.UserValves()

        anchor_n = (
            user_valves.anchor_message_count
            if user_valves.anchor_message_count is not None
            else self.valves.anchor_message_count_default
        )
        recent_n = (
            user_valves.recent_message_count
            if user_valves.recent_message_count is not None
            else self.valves.recent_message_count_default
        )

        # Only the trailing user message is the active prompt. During OWUI's
        # recursive tool loop, assistant/tool messages follow that user turn;
        # extracting and re-appending the older user message would corrupt the
        # function-call/result ordering.
        current_user_message = (
            messages[-1] if messages[-1].get("role") == "user" else None
        )

        system_messages = [m for m in messages if m.get("role") == "system"]
        history_messages = [
            m
            for m in messages
            if m.get("role") != "system" and m is not current_user_message
        ]

        current_user_tokens = (
            self.count_message_tokens(current_user_message)
            if current_user_message
            else 0
        )
        request_input_budget = self.calculate_request_input_budget(
            model_name, user_valves.context_target_percent
        )
        system_tokens = self.count_messages_tokens(system_messages)
        history_tokens = self.count_messages_tokens(history_messages)
        request_overhead_tokens = sum(
            self.count_tokens(
                json.dumps(body.get(field), ensure_ascii=False, default=str)
            )
            for field in ("tools", "extra_tools")
            if body.get(field)
        )
        budget_for_history = (
            request_input_budget
            - current_user_tokens
            - system_tokens
            - request_overhead_tokens
        )

        self.debug_log(
            1,
            f"Budget check: history={history_tokens:,} vs budget_for_history={budget_for_history:,} "
            f"(request_budget={request_input_budget:,}, system={system_tokens:,}, tools={request_overhead_tokens:,}, current_user={current_user_tokens:,}, "
            f"pct={user_valves.context_target_percent}, anchor={anchor_n}, recent={recent_n})",
            "📊",
        )

        persistable = self._is_persistable_chat_id(__chat_id__)
        state = (await self._load_context_state(__chat_id__)) if persistable else None
        state = state or {}

        covered_upto = min(anchor_n, len(history_messages))
        blocks: List[Dict[str, str]] = []
        if state:
            stored_upto = min(
                int(state.get("covered_upto", covered_upto)), len(history_messages)
            )
            stored_hash = state.get("covered_hash")
            # Staleness check: if earlier messages were edited/deleted since the
            # last fold, the stored blocks no longer match - start over rather
            # than risk an inconsistent/incorrect summary.
            if stored_hash == self._hash_history_prefix(history_messages[:stored_upto]):
                covered_upto = stored_upto
                blocks = state.get("blocks", [])

        budget = max(budget_for_history, 0)
        estimated_request_tokens = (
            system_tokens
            + history_tokens
            + current_user_tokens
            + request_overhead_tokens
        )
        over_cap = (
            history_tokens > budget or estimated_request_tokens > request_input_budget
        )
        force_fold = False
        prompted = False
        warning_last_asked = int(state.get("warning_last_asked_msg_count", 0))
        total_message_count = len(messages)

        if not over_cap:
            warning_percent = self._current_model_info.get(
                "warning_percent", NO_TABLE_ROWS_FALLBACK_WARNING_PERCENT
            )
            turns_elapsed = (total_message_count - warning_last_asked) // 2
            should_prompt = (
                self.valves.enable_warning_prompt
                and __event_call__
                and persistable
                and budget > 0
                and history_tokens >= budget * warning_percent / 100
                and (
                    warning_last_asked == 0
                    or turns_elapsed >= self.valves.warning_reprompt_interval_turns
                )
            )
            if should_prompt:
                force_fold = await self._ask_compress_now(
                    __event_call__, history_tokens, budget
                )
                prompted = True
                warning_last_asked = total_message_count
                self.debug_log(
                    1,
                    f"Warning-threshold prompt shown at {history_tokens:,}/{budget:,} tokens - "
                    f"user {'accepted' if force_fold else 'declined/timed out'}",
                    "⚠️",
                )

            if not force_fold:
                if prompted and persistable:
                    await self._save_context_state(
                        __chat_id__,
                        {
                            "covered_upto": covered_upto,
                            "covered_hash": self._hash_history_prefix(
                                history_messages[:covered_upto]
                            ),
                            "blocks": blocks,
                            "tool_summaries": state.get("tool_summaries", {}),
                            "warning_last_asked_msg_count": warning_last_asked,
                        },
                    )
                return body

        try:
            candidate, new_covered_upto, new_blocks, stats = (
                await self.build_context_window(
                    history_messages,
                    budget,
                    anchor_n,
                    recent_n,
                    covered_upto,
                    blocks,
                    force=force_fold,
                    preserve_latest_unit=current_user_message is None,
                )
            )
        except Exception as e:
            self.debug_log(
                1, f"Context trimming failed, leaving conversation as-is: {e}", "❌"
            )
            if self.valves.debug_level >= 2:
                traceback.print_exc()
            return body

        candidate, tool_summary_cache, tool_stats = (
            await self.compact_tool_results_to_budget(
                candidate,
                budget,
                persisted_cache=state.get("tool_summaries", {}),
            )
        )

        if persistable and (stats["folded"] or prompted or tool_stats["compacted"]):
            new_hash = self._hash_history_prefix(history_messages[:new_covered_upto])
            await self._save_context_state(
                __chat_id__,
                {
                    "covered_upto": new_covered_upto,
                    "covered_hash": new_hash,
                    "blocks": new_blocks,
                    "tool_summaries": tool_summary_cache,
                    "warning_last_asked_msg_count": warning_last_asked,
                },
            )

        final_messages = system_messages + candidate
        if current_user_message:
            final_messages.append(current_user_message)

        final_tokens = (
            self.count_messages_tokens(final_messages) + request_overhead_tokens
        )

        status_parts = [
            f"kept {stats['kept']}/{len(history_messages)} messages verbatim"
        ]
        if stats["summarized_count"]:
            status_parts.append(
                f"{stats['summarized_count']} older message(s) summarized across "
                f"{stats['block_count']} block(s)"
            )
            if stats["folded"]:
                status_parts.append(
                    "folded 1 new block this turn (user-approved early compression)"
                    if prompted
                    else "folded 1 new block this turn"
                )
        if tool_stats["compacted"]:
            status_parts.append(
                f"semantically compacted {tool_stats['compacted']} oversized tool result(s)"
            )
        if legacy_details_removed:
            status_parts.append(
                f"removed {legacy_details_removed:,} characters of legacy UI details"
            )
        original_tokens = (
            system_tokens
            + history_tokens
            + current_user_tokens
            + request_overhead_tokens
        )
        status_msg = (
            f"Trimmed conversation history: {', '.join(status_parts)} "
            f"({original_tokens:,}→{final_tokens:,} tokens)"
        )

        if __event_emitter__ and (stats["folded"] or tool_stats["compacted"]):
            try:
                await __event_emitter__(
                    {
                        "type": "status",
                        "data": {"description": status_msg, "done": True},
                    }
                )
            except Exception:
                pass

        self.debug_log(1, status_msg, "🔧")

        final_budget = request_input_budget
        if final_tokens > final_budget:
            error_message = (
                "Context compaction could not fit this request within the model budget "
                f"({final_tokens:,} > {final_budget:,} estimated tokens; "
                f"summary calls {self._summary_calls_used}/"
                f"{self.valves.max_summary_calls_per_request})."
            )
            if __event_emitter__:
                try:
                    await __event_emitter__(
                        {
                            "type": "status",
                            "data": {
                                "description": error_message,
                                "done": True,
                                "level": "error",
                            },
                        }
                    )
                except Exception:
                    pass
            raise ContextBudgetExceededError(error_message)

        body["messages"] = final_messages
        return body


