MARKER_PLACEHOLDER = "<!--openai_responses:marker-->"

import re as _re
_DETAILS_BLOCK_RE = _re.compile(r'<details\b[^>]*>.*?</details>', _re.DOTALL)


def _strip_details_blocks(text: str) -> str:
    """Remove UI-only <details> blocks from assistant history text.

    These blocks (<details type="tool_calls">, <details type="reasoning">)
    are rendered by Open WebUI but must not be sent back to the API as
    conversation context — they confuse the model and waste tokens.
    """
    return _DETAILS_BLOCK_RE.sub('', text).strip()


def strip_marker_placeholders(text: str | None) -> str:
    """Remove internal marker placeholders that should never be user-visible."""

    return (text or "").replace(MARKER_PLACEHOLDER, "")


class HistoryStore(Protocol):
    def save_items(
        self,
        chat_key: dict,
        message_id: str,
        items: list[dict],
        model_id: str,
    ) -> list[str]:
        """Persist items and return their ULIDs."""

    def load_items(
        self,
        chat_key: dict,
        item_ids: list[str],
        model_id: str | None = None,
    ) -> dict[str, dict]:
        """Return {ulid: payload} for requested items (filtered by model if given)."""


def _render_system_content(content: object) -> str:
    if isinstance(content, str):
        return content
    if isinstance(content, dict):
        if "text" in content:
            return str(content.get("text", ""))
        return str(content)
    if isinstance(content, Iterable):
        parts: list[str] = []
        for block in content:
            if isinstance(block, dict) and "text" in block:
                parts.append(str(block.get("text", "")))
            else:
                parts.append(str(block))
        return " ".join(part for part in parts if part).strip()
    return str(content)


def _to_input_block(block: dict) -> dict:
    if isinstance(block, str):
        return {"type": "input_text", "text": block}
    if not isinstance(block, dict):
        return {"type": "input_text", "text": str(block)}
    kind = block.get("type")
    if kind == "text":
        return {"type": "input_text", "text": block.get("text", "")}
    if kind == "image_url":
        url = (block.get("image_url") or {}).get("url")
        return {"type": "input_image", "image_url": url}
    if kind == "input_file":
        return {"type": "input_file", "file_id": block.get("file_id")}
    return block


class HistoryManager:
    """Bridge between Open WebUI messages and Responses API history."""

    def __init__(self, store: HistoryStore):
        self._store = store

    def _collect_required_item_ids(self, messages: list[dict]) -> set[str]:
        required_item_ids: set[str] = set()
        for msg in messages:
            if msg.get("role") != "assistant":
                continue
            content = msg.get("content")
            if not isinstance(content, str):
                continue
            if not contains_marker(content):
                continue
            for marker in extract_markers(content, parsed=True):
                ulid = marker.get("ulid")
                if isinstance(ulid, str):
                    required_item_ids.add(ulid)
        return required_item_ids

    def build_input_from_messages(
        self,
        *,
        messages: list[dict],
        chat_key: dict | None,
        model_id: str | None,
        openwebui_model_id: str | None,
    ) -> Tuple[list[dict], str | None]:
        """Build Responses ``input`` items plus instructions from messages."""

        items_lookup: dict[str, dict] = {}
        target_model_id = openwebui_model_id or model_id

        if chat_key and target_model_id:
            required_item_ids = self._collect_required_item_ids(messages)
            if required_item_ids:
                try:
                    items_lookup = self._store.load_items(
                        chat_key=chat_key,
                        item_ids=list(required_item_ids),
                        model_id=target_model_id,
                    )
                except Exception:  # pragma: no cover - defensive fallback
                    items_lookup = {}

        input_items: list[dict] = []
        instructions: str | None = None

        for msg in messages:
            role = msg.get("role")
            if role == "system":
                instructions = _render_system_content(msg.get("content"))
                continue

            if role == "tool":
                content = msg.get("content", "")
                if isinstance(content, list):
                    text_parts: list[str] = []
                    for block in content:
                        if not isinstance(block, dict):
                            text_parts.append(str(block))
                        elif block.get("type") in {"text", "input_text"}:
                            text_parts.append(str(block.get("text", "")))
                    content = "".join(text_parts)
                input_items.append(
                    {
                        "type": "function_call_output",
                        "call_id": str(msg.get("tool_call_id") or ""),
                        "output": str(content or ""),
                    }
                )
                continue

            if role == "user":
                blocks = msg.get("content") or []
                if isinstance(blocks, str):
                    blocks = [{"type": "text", "text": blocks}]
                content_blocks = [_to_input_block(b) for b in blocks if b is not None]
                if content_blocks:
                    input_items.append({"role": "user", "content": content_blocks})
                continue

            if role == "developer":
                blocks = msg.get("content") or []
                if isinstance(blocks, str):
                    blocks = [{"type": "text", "text": blocks}]
                content_blocks = [_to_input_block(b) for b in blocks if b is not None]
                if content_blocks:
                    input_items.append({"role": "developer", "content": content_blocks})
                continue

            if role != "assistant":
                continue

            # Open WebUI owns the tool loop. Provider-native reasoning items
            # needed for stateless Responses continuation are carried through
            # its reasoning_details sidecar and restored before function calls.
            for detail in msg.get("reasoning_details") or []:
                if not isinstance(detail, dict) or detail.get("type") != "openai_responses":
                    continue
                item = detail.get("item")
                if isinstance(item, dict) and item.get("type") == "reasoning":
                    restored = dict(item)
                    restored.pop("reasoning_details", None)
                    input_items.append(restored)

            raw = msg.get("content", "") or ""
            if not isinstance(raw, str):
                raw = str(raw)

            # Strip UI-only <details> blocks before sending as API history.
            raw = _strip_details_blocks(raw)

            if not contains_marker(raw):
                text = raw.strip()
                if text:
                    input_items.append(
                        {"role": "assistant", "content": [{"type": "output_text", "text": text}]}
                    )
                for tool_call in msg.get("tool_calls") or []:
                    if not isinstance(tool_call, dict):
                        continue
                    function = tool_call.get("function") or {}
                    call_id = str(tool_call.get("id") or "")
                    name = str(function.get("name") or "")
                    arguments = function.get("arguments", "{}")
                    if not isinstance(arguments, str):
                        arguments = json.dumps(arguments)
                    if call_id and name:
                        input_items.append(
                            {
                                "type": "function_call",
                                "call_id": call_id,
                                "name": name,
                                "arguments": arguments,
                            }
                        )
                continue

            for segment in split_text_by_markers(raw):
                if segment.get("type") == "marker":
                    payload = segment.get("marker") or ""
                    try:
                        parsed = parse_marker(payload)
                    except Exception:
                        continue
                    ulid = parsed.get("ulid")
                    if isinstance(ulid, str):
                        item = items_lookup.get(ulid)
                        if item is not None:
                            input_items.append(item)
                    continue

                if segment.get("type") == "text":
                    text = (segment.get("text") or "").strip()
                    if text:
                        input_items.append(
                            {
                                "role": "assistant",
                                "content": [{"type": "output_text", "text": text}],
                            }
                        )

            # Legacy marker-bearing messages can also carry Open WebUI-native
            # tool_calls. Preserve those after restoring any side-table items.
            for tool_call in msg.get("tool_calls") or []:
                if not isinstance(tool_call, dict):
                    continue
                function = tool_call.get("function") or {}
                call_id = str(tool_call.get("id") or "")
                name = str(function.get("name") or "")
                arguments = function.get("arguments", "{}")
                if not isinstance(arguments, str):
                    arguments = json.dumps(arguments)
                if call_id and name:
                    input_items.append(
                        {
                            "type": "function_call",
                            "call_id": call_id,
                            "name": name,
                            "arguments": arguments,
                        }
                    )

        return input_items, instructions

    def persist_items_for_message(
        self,
        *,
        chat_key: dict | None,
        message_id: str,
        items: list[dict],
        model_id: str,
        openwebui_model_id: str | None,
        current_assistant_text: str,
        marker_placeholder: str = MARKER_PLACEHOLDER,
    ) -> str:
        """Persist items and append wrapped markers to assistant text."""

        if not items:
            return strip_marker_placeholders(current_assistant_text)
        if not chat_key or not openwebui_model_id:
            return strip_marker_placeholders(current_assistant_text)

        try:
            ulids = self._store.save_items(
                chat_key=chat_key,
                message_id=message_id,
                items=items,
                model_id=openwebui_model_id,
            )
        except Exception:  # pragma: no cover - defensive fallback
            return strip_marker_placeholders(current_assistant_text)

        updated_text = current_assistant_text or ""
        for ulid, payload in zip(ulids, items):
            item_type = str(payload.get("type", "unknown"))
            raw_payload = build_marker_payload(
                item_type=item_type,
                ulid=ulid,
                metadata={"model": openwebui_model_id},
            )
            marker_text = wrap_marker(raw_payload)
            if marker_placeholder and marker_placeholder in updated_text:
                updated_text = updated_text.replace(marker_placeholder, marker_text, 1)
            else:
                updated_text += marker_text

        if marker_placeholder and marker_placeholder in updated_text:
            updated_text = updated_text.replace(marker_placeholder, "")

        return strip_marker_placeholders(updated_text)


__all__ = ["HistoryManager", "HistoryStore", "MARKER_PLACEHOLDER", "strip_marker_placeholders"]

# === domain/tools.py ===
"""Tool definitions, registry/executor interfaces, and merge policy.

This module translates tool definitions from multiple sources into the
OpenAI Responses ``tools`` array while enforcing capability gating,
strict JSON Schema handling, and deterministic deduplication. See
``docs/tools_and_extra_tools.md`` for the authoritative contract.
"""

from copy import deepcopy
from dataclasses import dataclass
from typing import Any, Iterable, Literal, Protocol, Type

from pydantic import (
    BaseModel,
    ConfigDict,
    Field,
    ValidationError,
    field_validator,
    model_validator,
)

# [build.py] internal imports removed in monolith:
# from openai_responses_manifold.core.config import RuntimeConfig
# from openai_responses_manifold.core.logging import get_logger

# [build.py] internal imports removed in monolith:
# from .types import ToolCall, ToolResult

import json as _json

_logger = get_logger(__name__)


def _stable_json_key(value: Any) -> str:
    """Produce a stable key for deduplicating tool definitions."""

    try:
        return _json.dumps(value, sort_keys=True)
    except Exception:
        return str(id(value))


@dataclass
class ToolDefinition:
    """Internal representation of a tool definition."""

    name: str
    description: str
    parameters: dict
    strict: bool
    source: Literal["registry", "filter", "body", "mcp", "builtin"]


class ToolRegistry(Protocol):
    def get(self, name: str) -> ToolDefinition | None:
        ...

    def iter_definitions(self) -> Iterable[ToolDefinition]:
        ...


class ToolExecutor(Protocol):
    async def execute(self, calls: list[ToolCall]) -> list[ToolResult]:
        ...


def _ensure_object_schema(schema: object) -> dict:
    if isinstance(schema, dict):
        return deepcopy(schema)
    return {"type": "object", "properties": {}}


def _make_nullable(type_value: object) -> object:
    if isinstance(type_value, list):
        if "null" in type_value:
            return type_value
        return [*type_value, "null"]
    if isinstance(type_value, str):
        if type_value == "null":
            return type_value
        return [type_value, "null"]
    return type_value


def _append_null_variant(variants: list) -> list:
    if any(isinstance(variant, dict) and variant.get("type") == "null" for variant in variants):
        return variants
    return [*variants, {"type": "null"}]


def _infer_schema_type(
    schema: dict,
    property_name: str | None = None,
    *,
    allow_semantic_inference: bool = False,
) -> str | None:
    """Infer an omitted JSON Schema type from validation keywords.

    Some Open WebUI tool-server schemas arrive with constrained ``anyOf``
    branches such as ``{"minimum": 1}``. OpenAI rejects those branches because
    each branch must declare a type. We infer only where the schema already
    carries type-specific keywords.
    """

    if "properties" in schema or "additionalProperties" in schema:
        return "object"
    if "items" in schema:
        return "array"
    if any(key in schema for key in ("minLength", "maxLength", "pattern", "format")):
        return "string"
    name = (property_name or "").lower()
    description = str(schema.get("description") or "").lower()
    if any(
        key in schema
        for key in ("minimum", "maximum", "exclusiveMinimum", "exclusiveMaximum", "multipleOf")
    ):
        if any(
            token in name
            for token in ("line", "count", "index", "offset", "limit", "size", "length")
        ):
            return "integer"
        return "number"

    enum = schema.get("enum")
    if isinstance(enum, list) and enum:
        non_null = [value for value in enum if value is not None]
        if non_null and all(isinstance(value, bool) for value in non_null):
            return "boolean"
        if non_null and all(isinstance(value, int) and not isinstance(value, bool) for value in non_null):
            return "integer"
        if non_null and all(isinstance(value, (int, float)) and not isinstance(value, bool) for value in non_null):
            return "number"
        if non_null and all(isinstance(value, str) for value in non_null):
            return "string"

    const = schema.get("const")
    if isinstance(const, bool):
        return "boolean"
    if isinstance(const, int) and not isinstance(const, bool):
        return "integer"
    if isinstance(const, float):
        return "number"
    if isinstance(const, str):
        return "string"
    if const is None and "const" in schema:
        return "null"

    if not allow_semantic_inference:
        return None
    if any(
        token in name
        for token in ("line", "count", "index", "offset", "limit", "size", "length", "tail")
    ):
        return "integer"
    if name in {
        "include",
        "exclude",
        "pattern",
        "query",
        "path",
        "directory",
        "file",
        "glob",
        "type",
    }:
        return "string"
    if name == "wait" or "seconds to wait" in description:
        return "number"
    if "last n " in description or "line number" in description or "1-indexed" in description:
        return "integer"
    if "glob pattern" in description or "type filter" in description:
        return "string"

    return None


# Keywords that are valid JSON Schema but are not permitted by OpenAI's
# strict function-calling subset.  If any of these appear anywhere in a
# tool's parameter schema we must NOT enable strict mode for that tool.
_OPENAI_STRICT_INCOMPATIBLE_KEYS: frozenset[str] = frozenset({
    "propertyNames",
    "patternProperties",
    "unevaluatedProperties",
    "unevaluatedItems",
    "if",
    "then",
    "else",
    "not",
    "$comment",
    "contentSchema",
    "contains",
    "prefixItems",
})

_JSON_SCHEMA_SHAPE_KEYS: frozenset[str] = frozenset({
    "$ref",
    "allOf",
    "anyOf",
    "const",
    "enum",
    "items",
    "oneOf",
    "properties",
    "type",
})


def _schema_is_strict_compatible(schema: object) -> bool:
    """Return False if the schema contains any keyword banned in strict mode."""

    def check_schema(value: object) -> bool:
        if isinstance(value, dict):
            if _OPENAI_STRICT_INCOMPATIBLE_KEYS.intersection(value):
                return False
            if not _JSON_SCHEMA_SHAPE_KEYS.intersection(value):
                return False

            if value.get("additionalProperties") not in (None, False):
                return False

            properties = value.get("properties")
            if isinstance(properties, dict):
                if not all(check_schema(prop) for prop in properties.values()):
                    return False

            items = value.get("items")
            if isinstance(items, dict) and not check_schema(items):
                return False
            if isinstance(items, list) and not all(check_schema(item) for item in items):
                return False

            for combiner in ("anyOf", "oneOf", "allOf"):
                variants = value.get(combiner)
                if isinstance(variants, list) and not all(check_schema(v) for v in variants):
                    return False

            return True

        if isinstance(value, list):
            return all(check_schema(item) for item in value)
        return True

    if isinstance(schema, dict):
        return check_schema(schema)
    if isinstance(schema, list):
        return all(check_schema(item) for item in schema)
    return True


def _strictify_schema(schema: dict, property_name: str | None = None) -> dict:
    """Recursively enforce strict JSON Schema semantics for objects."""

    schema = _ensure_object_schema(schema)
    if "type" not in schema:
        inferred_type = _infer_schema_type(schema, property_name)
        if inferred_type is not None:
            schema["type"] = inferred_type

    for combiner in ("anyOf", "oneOf", "allOf"):
        variants = schema.get(combiner)
        if isinstance(variants, list):
            schema[combiner] = [
                _strictify_schema(variant, property_name=property_name)
                if isinstance(variant, dict)
                else variant
                for variant in variants
            ]

    schema_type = schema.get("type")
    if schema_type == "object" or (
        isinstance(schema_type, list) and "object" in schema_type
    ):
        properties = schema.get("properties")
        original_required = set(schema.get("required") or [])
        if not isinstance(properties, dict):
            properties = {}

        strict_props: dict[str, dict] = {}
        required: list[str] = []
        for prop_name, prop_schema in properties.items():
            strict_prop = _strictify_schema(prop_schema, property_name=prop_name)
            if prop_name not in original_required:
                current_type = strict_prop.get("type")
                if current_type is not None:
                    strict_prop["type"] = _make_nullable(current_type)
                elif isinstance(strict_prop.get("anyOf"), list):
                    strict_prop["anyOf"] = _append_null_variant(strict_prop["anyOf"])
                elif isinstance(strict_prop.get("oneOf"), list):
                    strict_prop["oneOf"] = _append_null_variant(strict_prop["oneOf"])
                else:
                    strict_prop = {"anyOf": [strict_prop, {"type": "null"}]}
            strict_props[prop_name] = strict_prop
            required.append(prop_name)

        schema["properties"] = strict_props
        schema["required"] = required
        schema["additionalProperties"] = False

    items = schema.get("items")
    if isinstance(items, dict):
        schema["items"] = _strictify_schema(items, property_name=property_name)

    return schema


def _repair_schema_for_openai(
    schema: object,
    property_name: str | None = None,
    *,
    allow_semantic_inference: bool = False,
) -> object:
    """Repair schemas that OpenAI rejects even outside strict mode.

    Open Terminal/direct tool-server integrations can provide optional numeric
    parameters as ``anyOf: [{"minimum": 1}, {"type": "null"}]``. That is not
    accepted by the OpenAI Responses API because constrained branches still
    need a concrete ``type``. This lighter repair runs before optional strict
    conversion so it applies regardless of the strict valve.
    """

    if isinstance(schema, list):
        return [
            _repair_schema_for_openai(item, property_name=property_name)
            for item in schema
        ]
    if not isinstance(schema, dict):
        return schema

    repaired = deepcopy(schema)
    if "type" not in repaired:
        inferred_type = _infer_schema_type(
            repaired,
            property_name,
            allow_semantic_inference=allow_semantic_inference,
        )
        if inferred_type is not None:
            repaired["type"] = inferred_type

    for combiner in ("anyOf", "oneOf", "allOf"):
        variants = repaired.get(combiner)
        if isinstance(variants, list):
            repaired[combiner] = [
                _repair_schema_for_openai(
                    variant,
                    property_name=property_name,
                    allow_semantic_inference=True,
                )
                for variant in variants
            ]

    properties = repaired.get("properties")
    if isinstance(properties, dict):
        repaired["properties"] = {
            prop_name: _repair_schema_for_openai(prop_schema, property_name=prop_name)
            for prop_name, prop_schema in properties.items()
        }

    items = repaired.get("items")
    if isinstance(items, dict):
        repaired["items"] = _repair_schema_for_openai(items, property_name=property_name)
    elif isinstance(items, list):
        repaired["items"] = [
            _repair_schema_for_openai(item, property_name=property_name)
            for item in items
        ]

    return repaired


class FunctionTool(BaseModel):
    """Spec-compliant function tool definition for the Responses API."""

    type: Literal["function"] = "function"
    name: str
    description: str | None = None
    parameters: dict[str, Any] = Field(
        default_factory=lambda: {"type": "object", "properties": {}}
    )
    strict: bool | None = None

    model_config = ConfigDict(extra="forbid")

    @model_validator(mode="before")
    @classmethod
    def _normalize_shapes(cls, data: Any) -> Any:
        """Accept both Responses- and legacy Chat Completions-style tool shapes."""

        if not isinstance(data, dict):
            return data

        # Already Responses-style (top-level name/parameters)
        if "name" in data and ("parameters" in data or "description" in data):
            return data

        # Legacy shape: {"type": "function", "function": {...}}
        fn = data.get("function")
        if isinstance(fn, dict):
            return {
                "type": data.get("type", "function"),
                "name": fn.get("name"),
                "description": fn.get("description"),
                "parameters": fn.get("parameters"),
                "strict": data.get("strict"),
            }

        return data

    @field_validator("parameters", mode="before")
    @classmethod
    def _ensure_params(cls, value: object) -> dict[str, Any]:
        return _ensure_object_schema(value)


class WebSearchTool(BaseModel):
    """Web search tool definition."""

    type: Literal["web_search"] = "web_search"
    search_context_size: Literal["low", "medium", "high"] | None = None
    user_location: dict[str, Any] | None = None
    filters: dict[str, Any] | None = None
    external_web_access: bool | None = None

    model_config = ConfigDict(extra="forbid")


class McpTool(BaseModel):
    """Remote MCP tool connector definition."""

    type: Literal["mcp"] = "mcp"
    server_label: str
    server_url: str
    require_approval: bool | None = None
    allowed_tools: list[str] | None = None
    headers: dict[str, str] | None = None

    model_config = ConfigDict(extra="forbid")


class CodeInterpreterTool(BaseModel):
    """Code interpreter tool definition."""

    type: Literal["code_interpreter"] = "code_interpreter"
    container: dict[str, Any] = Field(default_factory=lambda: {"type": "auto"})

    model_config = ConfigDict(extra="forbid")


ToolModel = FunctionTool | WebSearchTool | McpTool | CodeInterpreterTool
_TOOL_MODEL_MAP: dict[str, Type[ToolModel]] = {
    "function": FunctionTool,
    "web_search": WebSearchTool,
    "mcp": McpTool,
    "code_interpreter": CodeInterpreterTool,
}


def _coerce_tool(raw: dict) -> dict | None:
    """Validate and normalize a raw tool dict against the known models."""

    tool_type = raw.get("type")
    if not isinstance(tool_type, str):
        return None
    cleaned = deepcopy(raw)
    cleaned.pop("source", None)
    model = _TOOL_MODEL_MAP.get(tool_type)
    if model is None:
        return cleaned
    try:
        return model.model_validate(cleaned).model_dump(exclude_none=True)
    except ValidationError as exc:
        name = cleaned.get("name") if isinstance(cleaned.get("name"), str) else None
        descriptor = f"{tool_type}:{name}" if name else str(tool_type)
        _logger.warning("Dropping tool %s after validation error: %s", descriptor, exc)
        return None


def _tool_identity(tool: dict) -> tuple[str | None, str | None]:
    tool_type = tool.get("type")
    if tool_type == "function":
        name = tool.get("name")
    elif tool_type == "mcp":
        name = tool.get("server_label") or tool.get("server_url")
    elif tool_type == "web_search":
        name = _stable_json_key(tool)
    else:
        name = tool.get("id") or tool.get("name")
    return (str(tool_type) if tool_type is not None else None, name)


def _definition_to_tool(defn: ToolDefinition) -> dict:
    return FunctionTool(
        name=defn.name,
        description=defn.description,
        parameters=_ensure_object_schema(defn.parameters),
        strict=defn.strict,
    ).model_dump(exclude_none=True)


class ToolPolicy:
    """Policy for building the OpenAI ``tools`` array for a turn."""

    @staticmethod
    def build_responses_tools(
        model_id: str,
        cfg: RuntimeConfig,
        registry: ToolRegistry,
        body_tools: list[dict] | None,
        extra_tools: list[dict] | None,
        mcp_tools: list[dict] | None,
        web_search_tools: list[dict] | None,
    ) -> list[dict]:
        # All supported models accept function calling and the built-in tools,
        # so tools are attached as requested; the API rejects anything a given
        # model does not support.
        ordered_tools: list[dict] = []

        def extend_tools(candidates: Iterable[dict]) -> None:
            for candidate in candidates:
                if not isinstance(candidate, dict):
                    continue
                tool = _coerce_tool(candidate)
                if tool:
                    ordered_tools.append(tool)

        extend_tools(body_tools or [])
        extend_tools(_definition_to_tool(d) for d in registry.iter_definitions())
        extend_tools(extra_tools or [])
        extend_tools(mcp_tools or [])
        extend_tools(web_search_tools or [])

        deduped: dict[tuple[str | None, str | None], dict] = {}
        for raw_tool in ordered_tools:
            tool_type = raw_tool.get("type")
            tool = deepcopy(raw_tool)
            if tool_type == "function":
                raw_params = tool.get("parameters") or {}
                strict_compatible = _schema_is_strict_compatible(raw_params)
                params = _repair_schema_for_openai(raw_params)
                tool["parameters"] = params
            if tool_type == "function" and cfg.ENABLE_STRICT_TOOL_CALLING:
                if strict_compatible:
                    tool["parameters"] = _strictify_schema(params)
                    tool["strict"] = True
                else:
                    _logger.debug(
                        "Skipping strict mode for tool %r: schema contains "
                        "keywords incompatible with OpenAI strict function calling.",
                        tool.get("name"),
                    )
            identity = _tool_identity(tool)
            if identity in deduped:
                deduped.pop(identity, None)
            deduped[identity] = tool

        return list(deduped.values())


__all__ = [
    "ToolDefinition",
    "ToolRegistry",
    "ToolExecutor",
    "ToolPolicy",
]

