_LOGGER = get_logger(__name__)

_CODE_INTERPRETER_EVENT_TYPES = {
    "response.code_interpreter_call.in_progress",
    "response.code_interpreter_call.interpreting",
    "response.code_interpreter_call.code.delta",
    "response.code_interpreter_call.code.done",
    "response.code_interpreter_call.completed",
}


def _response_error_message(response: dict[str, Any] | None, default: str) -> str:
    """Extract a human-readable error message from a response snapshot."""

    if isinstance(response, dict):
        error = response.get("error")
        if isinstance(error, dict):
            message = error.get("message")
            if isinstance(message, str) and message.strip():
                return message
        details = response.get("incomplete_details")
        if isinstance(details, dict):
            reason = details.get("reason")
            if isinstance(reason, str) and reason.strip():
                return reason
    return default

_SERVER_SIDE_TOOL_TYPES = {
    "web_search_call",
    "file_search_call",
    "image_generation_call",
    "mcp_call",
    "mcp_list_tools",
    "computer_call",
}

_TERMINAL_TOOL_STATUS_PHASES = {"done", "completed", "failed"}


def _server_tool_event_phase(event_type: str | None) -> tuple[str, str] | None:
    """Return (tool_type, phase) for Responses API server-side tool events."""

    if not isinstance(event_type, str) or not event_type.startswith("response."):
        return None
    body = event_type[len("response.") :]
    tool_type, sep, phase = body.rpartition(".")
    if not sep or tool_type not in _SERVER_SIDE_TOOL_TYPES:
        return None
    return tool_type, phase


def _server_tool_item_detail(item: dict[str, Any] | None) -> str:
    if not isinstance(item, dict):
        return ""

    action = item.get("action") if isinstance(item.get("action"), dict) else {}
    query = action.get("query") or item.get("query")
    if isinstance(query, str) and query.strip():
        return f" for `{query.strip()}`"

    queries = item.get("queries") or action.get("queries")
    if isinstance(queries, list):
        clean_queries = [str(q).strip() for q in queries if str(q).strip()]
        if clean_queries:
            joined = ", ".join(f"`{q}`" for q in clean_queries[:3])
            suffix = "…" if len(clean_queries) > 3 else ""
            return f" for {joined}{suffix}"

    name = item.get("name") or item.get("server_label") or action.get("name")
    if isinstance(name, str) and name.strip():
        return f" `{name.strip()}`"

    return ""


def _server_tool_sources_count(item: dict[str, Any] | None) -> int:
    if not isinstance(item, dict):
        return 0
    action = item.get("action") if isinstance(item.get("action"), dict) else {}
    sources = action.get("sources") or item.get("sources")
    return len(sources) if isinstance(sources, list) else 0


def _server_tool_status_description(
    tool_type: str,
    phase: str,
    item: dict[str, Any] | None = None,
) -> str | None:
    detail = _server_tool_item_detail(item)
    phase = (phase or "").lower()

    if tool_type == "web_search_call":
        if phase in {"added", "in_progress", "searching"}:
            return f"🔍 Searching the web{detail}…"
        if phase in {"done", "completed"}:
            source_count = _server_tool_sources_count(item)
            suffix = f" ({source_count} sources)." if source_count else "."
            return f"🔍 Web search complete{suffix}"
        if phase == "failed":
            return "🔍 Web search failed."

    if tool_type == "file_search_call":
        if phase in {"added", "in_progress", "searching"}:
            return f"📄 Searching files{detail}…"
        if phase in {"done", "completed"}:
            return "📄 File search complete."
        if phase == "failed":
            return "📄 File search failed."

    if tool_type == "image_generation_call":
        if phase in {"added", "in_progress", "generating"}:
            return "🎨 Generating image…"
        if phase in {"done", "completed"}:
            return "🎨 Image generation complete."
        if phase == "failed":
            return "🎨 Image generation failed."

    if tool_type == "mcp_list_tools":
        if phase in {"added", "in_progress"}:
            return f"🔌 Listing MCP tools{detail}…"
        if phase in {"done", "completed"}:
            return "🔌 MCP tool list complete."
        if phase == "failed":
            return "🔌 MCP tool list failed."

    if tool_type == "mcp_call":
        if phase in {"added", "in_progress"}:
            return f"🔌 Calling MCP tool{detail}…"
        if phase in {"done", "completed"}:
            return f"🔌 MCP tool complete{detail}."
        if phase == "failed":
            return f"🔌 MCP tool failed{detail}."

    if tool_type == "computer_call":
        if phase in {"added", "in_progress"}:
            return "🖥️ Using computer tool…"
        if phase in {"done", "completed"}:
            return "🖥️ Computer tool complete."
        if phase == "failed":
            return "🖥️ Computer tool failed."

    return None


async def _emit_server_tool_status(
    *,
    tool_type: str,
    phase: str,
    item: dict[str, Any] | None,
    state: TurnState,
    events: RuntimeEvents,
    logger: logging.Logger,
) -> None:
    description = _server_tool_status_description(tool_type, phase, item)
    if not description:
        return

    identifier = ""
    if isinstance(item, dict):
        identifier = str(item.get("id") or item.get("call_id") or item.get("name") or "")
    key = f"{tool_type}:{phase}:{identifier}:{description}"
    if key in state.server_tool_status_keys:
        return
    state.server_tool_status_keys.add(key)

    try:
        normalized_phase = (phase or "").lower()
        await events.status(
            description,
            done=normalized_phase in _TERMINAL_TOOL_STATUS_PHASES,
            level="error" if normalized_phase == "failed" else "info",
        )
    except Exception:
        logger.debug("Failed to emit server-side tool status", exc_info=True)


def _attach_responses_reasoning_details(event: dict[str, Any]) -> dict[str, Any]:
    """Carry native reasoning items through Open WebUI's tool-loop sidecar.

    Open WebUI converts provider output into assistant ``tool_calls`` before
    reinvoking a pipe. Its ``reasoning_details`` extension survives that
    conversion, while arbitrary Responses reasoning items do not. Attach a
    clean copy so encrypted/stateless continuation data can be reconstructed.
    """

    def enrich(item: Any) -> Any:
        if not isinstance(item, dict) or item.get("type") != "reasoning":
            return item
        native = deepcopy(item)
        native.pop("reasoning_details", None)
        enriched = dict(item)
        enriched["reasoning_details"] = [
            {"type": "openai_responses", "index": 0, "item": native}
        ]
        return enriched

    adapted = deepcopy(event)
    if isinstance(adapted.get("item"), dict):
        adapted["item"] = enrich(adapted["item"])
    response = adapted.get("response")
    if isinstance(response, dict) and isinstance(response.get("output"), list):
        response["output"] = [enrich(item) for item in response["output"]]
    return adapted


class ResponsesEngine:
    """Translate one OpenAI Responses API call for Open WebUI."""

    _TERMINAL_RESPONSE_EVENTS = {
        "response.completed",
        "response.failed",
        "response.incomplete",
        "response.error",
    }

    def __init__(
        self,
        client: OpenAIClient,
        history_manager: HistoryManager,
        logger: logging.Logger | None = None,
    ):
        self._client = client
        self._history_manager = history_manager
        self._logger = logger or _LOGGER

    async def stream_single_turn(
        self,
        request: dict[str, Any],
        ctx: TurnContext,
    ) -> AsyncIterator[dict[str, Any]]:
        """Stream exactly one provider response back to Open WebUI.

        Open WebUI 0.10.2 owns custom-function execution and reinvokes the
        pipe with function_call_output messages. Keeping the provider call
        single-shot prevents this manifold from duplicating OWUI's tool loop.
        """

        completed_items: list[dict[str, Any]] = []
        async for event in self._client.stream_responses(
            request,
            base_url=ctx.runtime_config.BASE_URL,
            api_key=ctx.runtime_config.API_KEY,
            max_retries=ctx.runtime_config.MAX_RETRIES,
        ):
            adapted = _attach_responses_reasoning_details(event)
            if adapted.get("type") == "response.output_item.done" and isinstance(
                adapted.get("item"), dict
            ):
                completed_items.append(adapted["item"])

            # Some compatible proxies return an empty completed.output even
            # though they streamed output_item.done events. Repair the terminal
            # snapshot before OWUI consumes it, otherwise OWUI discards the
            # function calls it already assembled.
            if adapted.get("type") == "response.completed":
                response = adapted.get("response") or {}
                if completed_items and not response.get("output"):
                    response["output"] = deepcopy(completed_items)
                    adapted["response"] = response

            yield adapted
            if adapted.get("type") in self._TERMINAL_RESPONSE_EVENTS:
                break

    async def run_task(self, request: dict[str, Any], ctx: TurnContext) -> str:
        request["stream"] = False
        request["store"] = False
        request["tools"] = None
        request["include"] = None
        response = await self._client.create_response(
            request,
            base_url=ctx.runtime_config.BASE_URL,
            api_key=ctx.runtime_config.API_KEY,
            max_retries=ctx.runtime_config.MAX_RETRIES,
        )
        try:
            outputs = response.get("output") or []
            text_blocks = []
            for item in outputs:
                if item.get("type") == "output_text":
                    content = item.get("content") or []
                    if isinstance(content, str):
                        text_blocks.append(str(content))
                    else:
                        for block in content:
                            if isinstance(block, dict) and block.get("type") == "output_text":
                                text_blocks.append(str(block.get("text", "")))
                if item.get("type") == "message":
                    for block in item.get("content", []):
                        if isinstance(block, dict) and block.get("type") in {"text", "output_text"}:
                            text_blocks.append(str(block.get("text", "")))
            return "".join(text_blocks)
        except Exception:
            return json.dumps(response)

    async def _stream_single_response(
        self,
        *,
        request: dict[str, Any],
        ctx: TurnContext,
        state: TurnState,
        events: RuntimeEvents,
        base_url: str,
        api_key: str,
    ) -> dict[str, Any] | None:
        response_payload: dict[str, Any] | None = None
        # Reset the per-response item collector. Items completed during this
        # stream are appended here (see _handle_event) so we can repair an
        # empty response.output on the terminal event.
        state.current_response_items = []
        async for event in self._client.stream_responses(
            request, base_url=base_url, api_key=api_key, max_retries=ctx.runtime_config.MAX_RETRIES
        ):
            response_payload = await self._handle_event(event, state, events, ctx)
            if event.get("type") in self._TERMINAL_RESPONSE_EVENTS:
                break
        # Defensive backfill: a conformant Responses API returns the complete
        # list of output items in the terminal response.completed snapshot.
        # If the upstream proxy returned an empty (or missing) output array but
        # we observed output_item.done events during the stream, reconstruct
        # response.output from those items so tool calls are not silently lost.
        if isinstance(response_payload, dict) and state.current_response_items:
            existing_output = response_payload.get("output") or []
            if not existing_output:
                self._logger.warning(
                    "_stream_single_response: response.completed returned empty "
                    "output array; backfilling %d item(s) from streamed "
                    "output_item.done events (upstream proxy spec violation). "
                    "item_types=%s",
                    len(state.current_response_items),
                    [it.get("type") for it in state.current_response_items],
                )
                response_payload["output"] = list(state.current_response_items)
        return response_payload

    async def _handle_event(
        self,
        event: dict[str, Any],
        state: TurnState,
        events: RuntimeEvents,
        ctx: TurnContext,
    ) -> dict[str, Any] | None:
        async def emit_status(description: str, **kwargs: Any) -> None:
            await events.status(description, **kwargs)

        event_type = event.get("type")

        if event_type in _CODE_INTERPRETER_EVENT_TYPES:
            await handle_code_interpreter_event(event, state, emit_status, self._logger)
            return None

        server_tool_phase = _server_tool_event_phase(event_type)
        if server_tool_phase:
            tool_type, phase = server_tool_phase
            await _emit_server_tool_status(
                tool_type=tool_type,
                phase=phase,
                item=None,
                state=state,
                events=events,
                logger=self._logger,
            )
            return None

        if event_type == "response.output_text.delta":
            # Only emit deltas that belong to a message item (the final text
            # response). Deltas during reasoning or function_call items are
            # internal and should not appear in the chat content.
            if state.current_output_item_type == "message":
                delta = event.get("delta") or ""
                if delta:
                    state.assistant_visible_text += delta
                    state.assistant_internal_text += delta
                    await events.delta(delta)
            else:
                self._logger.debug(
                    "_handle_event: SUPPRESSED output_text delta because "
                    "current_output_item_type=%r (delta_preview=%r)",
                    state.current_output_item_type,
                    (event.get("delta") or "")[:80],
                )
            return None

        if event_type == "response.reasoning_summary_text.done":
            text = event.get("text")
            if text:
                import html as _html
                block = (
                    f'<details type="reasoning" done="true">\n'
                    f"<summary>Thought</summary>\n"
                    f"{_html.escape(text)}\n"
                    f"</details>\n"
                )
                state.assistant_visible_text += block
                # Do not add to internal_text — reasoning blocks must not
                # appear in history context sent back to the API.
                await events.delta(block)
            return None

        if event_type == "response.output_text.annotation.added":
            annotation = event.get("annotation") or {}
            if annotation.get("type") == "url_citation":
                url = annotation.get("url")
                if not url:
                    return None
                url = _strip_tracking_params(url)
                # Only emit once per unique URL.
                if url not in state.citation_ordinals:
                    state.citation_ordinals[url] = len(state.citation_ordinals) + 1
                    source_name = _host_from_url(url) or "source"
                    title = annotation.get("title") or url
                    citation = Citation(
                        source_name=source_name,
                        url=url,
                        document=[title],
                        metadata={
                            "source": url,
                            "date_accessed": datetime.date.today().isoformat(),
                            "ordinal": state.citation_ordinals[url],
                        },
                    )
                    state.citations.append(citation)
                    payload = {
                        "source": {"name": citation.source_name, "url": citation.url},
                        "document": citation.document,
                        "metadata": [citation.metadata],
                    }
                    await events.source(payload)
                    await events.citation(payload)
            return None

        if event_type in {"response.output_item.added", "response.output_item.done"}:
            is_done = event_type == "response.output_item.done"
            item = event.get("item") or {}
            if item:
                item_type = str(item.get("type") or "")
                if is_done:
                    state.current_output_item_type = None
                    self._logger.debug(
                        "_handle_event: output item DONE type=%r", item_type
                    )
                else:
                    state.current_output_item_type = item_type
                    self._logger.debug(
                        "_handle_event: output item ADDED type=%r", item_type
                    )
                if item.get("type") == "code_interpreter_call":
                    await handle_code_interpreter_item(
                        item,
                        state,
                        events,
                        self._logger,
                        emit_status,
                        output_index=event.get("output_index"),
                    )
                elif item_type in _SERVER_SIDE_TOOL_TYPES:
                    await _emit_server_tool_status(
                        tool_type=item_type,
                        phase="done" if is_done else "added",
                        item=item,
                        state=state,
                        events=events,
                        logger=self._logger,
                    )
                    # Emit all sources from web_search_call.action.sources
                    if item_type == "web_search_call" and is_done:
                        action = item.get("action") if isinstance(item.get("action"), dict) else {}
                        for src in (action.get("sources") or []):
                            if not isinstance(src, dict):
                                continue
                            url = _strip_tracking_params(src.get("url") or "")
                            if not url or url in state.citation_ordinals:
                                continue
                            state.citation_ordinals[url] = len(state.citation_ordinals) + 1
                            title = src.get("title") or url
                            source_name = _host_from_url(url) or "source"
                            citation = Citation(
                                source_name=source_name,
                                url=url,
                                document=[title],
                                metadata={
                                    "source": url,
                                    "date_accessed": datetime.date.today().isoformat(),
                                    "ordinal": state.citation_ordinals[url],
                                },
                            )
                            state.citations.append(citation)
                            payload = {
                                "source": {"name": source_name, "url": url},
                                "document": [title],
                                "metadata": [citation.metadata],
                            }
                            await events.source(payload)
                            await events.citation(payload)
                if is_done:
                    # Track every completed output item for THIS response so we
                    # can backfill response.output if the terminal
                    # response.completed event returns an empty output array
                    # (some proxies drop it — a spec violation).
                    state.current_response_items.append(item)
                    self._record_structured_item(item, state, ctx.runtime_config)
            return None

        if event_type == "response.completed":
            response = event.get("response") or {}
            state.response_text = json.dumps(response)
            output_types = [
                (it or {}).get("type")
                for it in (response.get("output") or [])
            ]
            self._logger.debug(
                "_handle_event: response.completed output_item_types=%s",
                output_types,
            )
            return response

        if event_type == "response.incomplete":
            response = event.get("response") or {}
            state.error_message = _response_error_message(response, "Response incomplete")
            self._logger.debug(
                "_handle_event: response.incomplete error=%r", state.error_message
            )
            return response

        if event_type in {"response.failed", "response.error"}:
            response = event.get("response") or {}
            default = event.get("message") or "Response failed"
            state.error_message = _response_error_message(response, default)
            self._logger.debug(
                "_handle_event: %s error=%r", event_type, state.error_message
            )
            return response

        return None

    def _merge_usage(self, state: TurnState, response: dict[str, Any]) -> None:
        usage = _extract_usage(response)
        if usage:
            if state.usage is None:
                state.usage = dict(usage)
            else:
                for key, value in usage.items():
                    try:
                        state.usage[key] = state.usage.get(key, 0) + value
                    except Exception:
                        state.usage[key] = value

    def _extract_tool_calls(self, response: dict[str, Any]) -> list[ToolCall]:
        output_items = response.get("output") or []
        calls: list[ToolCall] = []
        for item in output_items:
            if item.get("type") != "function_call":
                continue
            call_id = str(item.get("call_id") or item.get("id") or "")
            name = str(item.get("name") or "")
            arguments = item.get("arguments")
            # The Responses API returns arguments as a JSON string already.
            # json.dumps-ing a string double-encodes it, so use it directly.
            if isinstance(arguments, str):
                arguments_json = arguments or "{}"
            elif arguments is not None:
                arguments_json = json.dumps(arguments)
            else:
                arguments_json = "{}"
            if call_id and name:
                calls.append(ToolCall(call_id=call_id, name=name, arguments_json=arguments_json))
        return calls

    def _extract_function_call_items(self, response: dict[str, Any]) -> list[dict[str, Any]]:
        """Return reasoning + function_call items from a response in output order.

        The Responses API requires that when a function_call is accompanied by
        a reasoning item, the reasoning item must appear in input immediately
        before its function_call. We collect all reasoning and function_call
        items preserving their original order.
        """
        return [
            item for item in (response.get("output") or [])
            if isinstance(item, dict) and item.get("type") in {"reasoning", "function_call"}
        ]

    def _tool_results_to_output_items(self, results: list[ToolResult]) -> list[dict[str, Any]]:
        items: list[dict[str, Any]] = []
        for result in results:
            # The Responses API only accepts type/call_id/output on
            # function_call_output items.  status and error are internal
            # domain fields and must not be forwarded.
            output = result.output
            if result.status != "ok" and result.error_message:
                output = result.error_message
            items.append(
                {
                    "type": "function_call_output",
                    "call_id": result.call_id,
                    "output": output,
                }
            )
        return items

    def _record_structured_item(self, item: dict[str, Any], state: TurnState, cfg: RuntimeConfig) -> None:
        state.structured_items.append(item)
        if _should_persist_item(item, cfg):
            # Add placeholder to both texts so marker injection can find it
            # in whichever one is used as the base for persist_items_for_message.
            state.assistant_internal_text += MARKER_PLACEHOLDER
            state.assistant_visible_text += MARKER_PLACEHOLDER


    async def _emit_log_citation(
        self,
        ctx: TurnContext,
        state: TurnState,
        events: RuntimeEvents,
    ) -> None:
        session_id = ctx.metadata.get("session_id") or OWUI_SESSION_ID.get()
        if not session_id:
            return

        logs = consume_session_logs(session_id)
        if not logs:
            return
        if not state.error_message:
            return

        source_name = "Error Logs"
        log_text = "\n".join(logs)
        max_len = 4000
        truncated = len(log_text) > max_len
        if truncated:
            log_text = log_text[:max_len] + "\n… (truncated)"

        citation = Citation(
            source_name=source_name,
            url=None,
            document=[log_text],
            metadata={
                "source": source_name,
                "total_lines": len(logs),
                "truncated": truncated,
            },
        )
        state.citations.append(citation)

        self._logger.debug(
            "Emitting log citation lines=%d truncated=%s", len(logs), truncated
        )
        await events.citation(
            {
                "document": citation.document,
                "metadata": [citation.metadata],
                "source": {"name": citation.source_name},
            }
        )


def _format_tool_call_delta(call: ToolCall, result: ToolResult) -> str:
    """Render a tool call + result as an Open WebUI <details type="tool_calls"> block."""
    import html as _h
    try:
        args_dict = json.loads(call.arguments_json or "{}")
        escaped_args = _h.escape(json.dumps(args_dict, ensure_ascii=False))
    except Exception:
        escaped_args = _h.escape(call.arguments_json or "")
    try:
        parsed_output = json.loads(result.output or "{}")
        escaped_result = _h.escape(json.dumps(parsed_output, ensure_ascii=False))
    except Exception:
        escaped_result = _h.escape(json.dumps(result.output or "", ensure_ascii=False))
    error_attr = ' error="true"' if result.status != "ok" else ""
    return (
        f'<details type="tool_calls" done="true" id="{_h.escape(call.call_id)}" '
        f'name="{_h.escape(call.name)}" '
        f'arguments="{escaped_args}" result="{escaped_result}" '
        f'files="" embeds=""{error_attr}>\n'
        f"<summary>Tool Executed</summary>\n"
        f"</details>\n"
    )


def _should_persist_item(item: dict[str, Any], cfg: RuntimeConfig) -> bool:
    item_type = item.get("type")
    if item_type in {"function_call", "function_call_output", "code_interpreter_call"}:
        return bool(cfg.PERSIST_TOOL_RESULTS)
    if item_type == "reasoning":
        # Always persist reasoning items that accompany tool calls (identified
        # by having no summary text — pure encrypted reasoning tokens) so they
        # can be echoed back alongside their function_call on future turns.
        # Also persist when the user has opted into conversation-level tokens.
        return bool(cfg.PERSIST_TOOL_RESULTS) or cfg.PERSIST_REASONING_TOKENS == "conversation"
    return False


def _extract_usage(response: dict[str, Any] | None) -> dict[str, Any]:
    if not isinstance(response, dict):
        return {}

    usage = response.get("usage")
    if isinstance(usage, dict):
        return usage

    nested = response.get("response")
    if isinstance(nested, dict):
        nested_usage = nested.get("usage")
        if isinstance(nested_usage, dict):
            return nested_usage

    return {}


def _strip_tracking_params(url: str) -> str:
    parsed = urlparse(url)
    if not parsed.query:
        return url
    query_params = parsed.query.split("&")
    filtered = [
        param
        for param in query_params
        if param
        and not param.lower().startswith("utm_")
        and not param.lower().startswith("ref=")
    ]
    return urlunparse(parsed._replace(query="&".join(filtered)))


def _host_from_url(url: str) -> str | None:
    try:
        return urlparse(url).hostname
    except Exception:
        return None


__all__ = ["ResponsesEngine"]

# === openwebui/store.py ===
"""Open WebUI-backed history store implementation.

This adapter owns the ``chat.chat["openai_responses_pipe"]`` layout and
implements the :class:`~openai_responses_manifold.domain.history.HistoryStore`
protocol so the domain layer can persist and reload structured items.
"""

import time
from typing import Any

# [build.py] internal imports removed in monolith:
# from openai_responses_manifold.core.markers import generate_ulid
# from openai_responses_manifold.domain.history import HistoryStore


class OpenWebUIHistoryStore(HistoryStore):
    """Persist history items using Open WebUI's ``Chats`` model."""

    VERSION = 3

    def __init__(self, chats_model: Any | None = None):
        if chats_model is not None:
            self._Chats = chats_model
        else:
            try:
                self._Chats = self._import_chats()
            except Exception:  # pragma: no cover - defensive fallback for missing deps
                self._Chats = None

    def _import_chats(self):  # pragma: no cover - exercised via injection in tests
        from open_webui.models.chats import Chats

        return Chats

    def save_items(
        self,
        chat_key: dict,
        message_id: str,
        items: list[dict],
        model_id: str,
    ) -> list[str]:
        if not self._Chats:
            return []
        chat_id = chat_key.get("chat_id") if isinstance(chat_key, dict) else None
        if not chat_id:
            return []

        chat = self._Chats.get_chat_by_id(chat_id)
        if not chat:
            return []

        pipe_root = chat.chat.setdefault("openai_responses_pipe", {"__v": self.VERSION})
        items_store = pipe_root.setdefault("items", {})
        messages_index = pipe_root.setdefault("messages_index", {})
        bucket = messages_index.setdefault(
            message_id, {"role": "assistant", "done": True, "item_ids": []}
        )

        now = int(time.time())
        created: list[str] = []
        for payload in items:
            ulid = generate_ulid()
            items_store[ulid] = {
                "model": model_id,
                "created_at": now,
                "payload": payload,
                "message_id": message_id,
            }
            bucket.setdefault("item_ids", []).append(ulid)
            created.append(ulid)

        self._Chats.update_chat_by_id(chat_id, chat.chat)
        return created

    def load_items(
        self, chat_key: dict, item_ids: list[str], model_id: str | None = None
    ) -> dict[str, dict]:
        if not self._Chats:
            return {}
        chat_id = chat_key.get("chat_id") if isinstance(chat_key, dict) else None
        if not chat_id:
            return {}

        chat = self._Chats.get_chat_by_id(chat_id)
        if not chat:
            return {}

        items_store = chat.chat.get("openai_responses_pipe", {}).get("items", {})
        result: dict[str, dict] = {}
        for ulid in item_ids:
            item = items_store.get(ulid)
            if not item:
                continue
            if model_id is not None and item.get("model") != model_id:
                continue
            result[ulid] = item.get("payload") or {}
        return result


__all__ = ["OpenWebUIHistoryStore"]

# === openwebui/events.py ===
"""Event adapter that maps domain runtime events to Open WebUI."""

import inspect
from typing import Any, Literal

# [build.py] internal imports removed in monolith:
# from openai_responses_manifold.domain.types import RuntimeEvents


class OpenWebUIRuntimeEvents(RuntimeEvents):
    """Wrap ``__event_emitter__`` with the runtime events protocol."""

    def __init__(self, emitter: Any):
        self._emitter = emitter
        self._logger = get_logger(__name__)

    async def _emit(self, payload: dict[str, Any]) -> None:
        if not self._emitter:
            self._logger.debug(
                "OpenWebUIRuntimeEvents._emit: NO emitter available, dropping "
                "payload type=%s",
                (payload or {}).get("type"),
            )
            return
        ptype = (payload or {}).get("type")
        pdata = (payload or {}).get("data") or {}
        content = pdata.get("content")
        self._logger.debug(
            "OpenWebUIRuntimeEvents._emit: type=%s done=%s content_len=%s",
            ptype,
            pdata.get("done"),
            len(content) if isinstance(content, str) else None,
        )
        if inspect.iscoroutinefunction(self._emitter):
            await self._emitter(payload)
            return
        result = self._emitter(payload)
        if inspect.isawaitable(result):
            await result

    async def status(self, description: str, *, done: bool = False, **extra: Any) -> None:
        await self._emit({"type": "status", "data": {"description": description, "done": done, **extra}})

    async def delta(self, content: str) -> None:
        await self._emit(
            {"type": "chat:message:delta", "data": {"role": "assistant", "content": content}}
        )

    async def replace(self, content: str) -> None:
        await self._emit(
            {"type": "chat:message", "data": {"role": "assistant", "content": content}}
        )

    async def citation(self, data: dict[str, Any]) -> None:
        await self._emit({"type": "citation", "data": data})

    async def source(self, data: dict[str, Any]) -> None:
        await self._emit({"type": "source", "data": data})

    async def chat_completion(self, data: dict[str, Any]) -> None:
        await self._emit({"type": "chat:completion", "data": data})

    async def notification(
        self,
        content: str,
        *,
        level: Literal["info", "success", "warning", "error"] = "info",
    ) -> None:
        await self._emit({"type": "notification", "data": {"type": level, "content": content}})


__all__ = ["OpenWebUIRuntimeEvents"]

# === openwebui/tools.py ===
"""Open WebUI tool registry and executor wrappers."""

import asyncio
import inspect
import json
from typing import Any, Iterable


# [build.py] internal imports removed in monolith:
# from openai_responses_manifold.domain.tools import ToolDefinition, ToolExecutor, ToolRegistry
# from openai_responses_manifold.domain.types import ToolCall, ToolResult


def _normalize_parameters(schema: object) -> dict:
    if isinstance(schema, dict):
        return schema
    return {"type": "object", "properties": {}}


class OpenWebUIToolRegistry(ToolRegistry):
    """Wrap ``__tools__`` registry into ``ToolDefinition`` objects."""

    def __init__(self, registry: dict[str, Any]):
        definitions: list[ToolDefinition] = []
        for entry in (registry or {}).values():
            spec = entry.get("spec") if isinstance(entry, dict) else None
            if not isinstance(spec, dict):
                continue
            name = spec.get("name")
            if not isinstance(name, str) or not name:
                continue
            definitions.append(
                ToolDefinition(
                    name=name,
                    description=str(spec.get("description") or ""),
                    parameters=_normalize_parameters(spec.get("parameters")),
                    strict=False,
                    source="registry",
                )
            )
        self._definitions = {d.name: d for d in definitions}

    def get(self, name: str) -> ToolDefinition | None:
        return self._definitions.get(name)

    def iter_definitions(self) -> Iterable[ToolDefinition]:
        return list(self._definitions.values())


class OpenWebUIToolExecutor(ToolExecutor):
    """Execute tool calls using callables from ``__tools__``.

    Some Open WebUI tool registrations (e.g. Open Terminal's run_command,
    list_files, glob_search, grep_search, write_file, etc. — any "direct"
    tool-server tool) carry no local ``callable`` at all. Open WebUI
    intentionally executes those client-side, in the browser, via a
    WebSocket round-trip (``__event_call__`` -> ``{'type': 'execute:tool',
    ...}``), exactly as its own native middleware does
    (utils/middleware.py: tool_call_handler). ``event_call``/``metadata``
    are threaded through here so this executor can dispatch those tools the
    same way instead of reporting "Tool not found".
    """

    def __init__(
        self,
        registry: dict[str, Any],
        *,
        parallel: bool = True,
        event_call: Any | None = None,
        metadata: dict[str, Any] | None = None,
    ):
        callables: dict[str, Any] = {}
        direct_entries: dict[str, dict[str, Any]] = {}
        for entry in (registry or {}).values():
            if not isinstance(entry, dict):
                continue
            name = entry.get("spec", {}).get("name") if isinstance(entry.get("spec"), dict) else None
            if not isinstance(name, str) or not name:
                continue
            fn = entry.get("callable")
            if fn is not None:
                callables[name] = fn
            elif entry.get("direct"):
                direct_entries[name] = entry
        self._callables = callables
        self._direct_entries = direct_entries
        self._parallel = parallel
        self._event_call = event_call
        self._metadata = metadata or {}

    async def execute(self, calls: list[ToolCall]) -> list[ToolResult]:
        if not self._parallel or len(calls) <= 1:
            return [await self._execute_one(call) for call in calls]

        # Only truly parallelize calls to *different* tool names.
        # Multiple calls to the same tool are serialized for thread safety
        # (e.g. two update_task calls on shared state must not race).
        # It is the model's responsibility not to issue dependent calls to
        # *different* tools in the same batch.
        seen_names: set[str] = set()
        has_duplicates = any(
            (name := call.name) in seen_names or seen_names.add(name)  # type: ignore[func-returns-value]
            for call in calls
        )
        if has_duplicates:
            return [await self._execute_one(call) for call in calls]

        return list(await asyncio.gather(*(self._execute_one(call) for call in calls)))

    async def _execute_direct(self, call: ToolCall, entry: dict[str, Any], args: dict) -> ToolResult:
        shared = await dispatch_direct_tool(
            name=call.name,
            arguments=args,
            entry=entry,
            event_call=self._event_call,
            metadata=self._metadata,
            call_id=call.call_id,
        )
        return ToolResult(
            call_id=call.call_id,
            output=shared.output_text,
            status=shared.status,
            error_message=shared.error_message,
        )

    async def _execute_one(self, call: ToolCall) -> ToolResult:
        try:
            args = json.loads(call.arguments_json or "{}")
        except json.JSONDecodeError as exc:  # pragma: no cover - defensive
            return ToolResult(
                call_id=call.call_id,
                output=f"Invalid JSON arguments: {exc}",
                status="error",
                error_message=str(exc),
            )

        fn = self._callables.get(call.name)
        if fn is None:
            direct_entry = self._direct_entries.get(call.name)
            if direct_entry is not None:
                return await self._execute_direct(call, direct_entry, args)
            return ToolResult(
                call_id=call.call_id,
                output="Tool not found",
                status="error",
                error_message="Tool not found",
            )

        try:
            if inspect.iscoroutinefunction(fn):
                value = await fn(**args)
            else:
                value = await asyncio.to_thread(fn, **args)
            output = json.dumps(value, default=str)
            return ToolResult(
                call_id=call.call_id,
                output=output,
                status="ok",
                error_message=None,
            )
        except Exception as exc:  # pragma: no cover - defensive
            return ToolResult(
                call_id=call.call_id,
                output=f"Tool error: {exc}",
                status="error",
                error_message=str(exc),
            )


__all__ = ["OpenWebUIToolRegistry", "OpenWebUIToolExecutor"]

# === openwebui/bridge.py ===
"""Helpers that translate Open WebUI inputs into Responses requests."""

import json
from typing import Any, Tuple

# [build.py] internal imports removed in monolith:
# from openai_responses_manifold.core import base_model
# from openai_responses_manifold.core.config import RuntimeConfig
# from openai_responses_manifold.domain.history import HistoryManager
# from openai_responses_manifold.domain.types import TurnContext


def build_turn_context(
    *,
    pipe_valves,
    user_valves,
    runtime_cfg: RuntimeConfig,
    __user__: dict | None,
    __metadata__: dict | None,
    body: dict | None = None,
) -> TurnContext:
    metadata = __metadata__ or {}

    # Open WebUI resolves workspace/custom model names to their base_model_id before
    # calling pipe(), storing it in body["model"] (e.g. "openai_responses.gpt-5.5").
    # Use that as the primary source; fall back to the valve MODEL_ID config.
    body_model = (body or {}).get("model") or ""
    model_id = base_model(body_model or runtime_cfg.MODEL_ID)

    owui_model_id = metadata.get("model_id") or body_model or None
    ctx_metadata = {
        "session_id": metadata.get("session_id"),
        "chat_id": metadata.get("chat_id"),
        "message_id": metadata.get("message_id"),
        "user_id": (__user__ or {}).get("id"),
        "user_email": (__user__ or {}).get("email"),
        "owui_model_id": owui_model_id,
    }
    return TurnContext(
        runtime_config=runtime_cfg,
        model_id=model_id,
        metadata=ctx_metadata,
    )


def map_completions_to_responses(
    *,
    body: dict,
    ctx: TurnContext,
    history_manager: HistoryManager,
    history_key: dict,
) -> Tuple[dict[str, Any], list[dict], list[dict]]:
    input_items, instructions = history_manager.build_input_from_messages(
        messages=body.get("messages") or [],
        chat_key=history_key,
        model_id=ctx.model_id,
        openwebui_model_id=ctx.metadata.get("owui_model_id"),
    )

    # We only support modern reasoning models, which reject temperature and
    # top_p entirely, so they are never forwarded.
    request: dict[str, Any] = {
        "model": ctx.model_id,
        "input": input_items,
        "instructions": instructions,
        "stream": True,
        "store": True,
        "top_logprobs": body.get("top_logprobs"),
        "max_output_tokens": body.get("max_tokens"),
        "reasoning": {"effort": body.get("reasoning_effort")}
        if body.get("reasoning_effort")
        else None,
    }

    base_tools = body.get("tools") or []
    extra_tools = body.get("extra_tools") or []
    return request, base_tools, extra_tools


def build_mcp_tools(cfg: RuntimeConfig) -> list[dict]:
    raw = cfg.REMOTE_MCP_SERVERS_JSON
    if not raw:
        return []

    try:
        entries = json.loads(raw)
    except Exception:
        return []

    tools: list[dict] = []
    if isinstance(entries, dict):
        entries = [entries]
    if not isinstance(entries, list):
        return []

    for entry in entries:
        if not isinstance(entry, dict):
            continue
        label = entry.get("server_label")
        url = entry.get("server_url")
        if not isinstance(label, str) or not isinstance(url, str):
            continue
        tool = {"type": "mcp", "server_label": label, "server_url": url}
        if "require_approval" in entry:
            tool["require_approval"] = entry.get("require_approval")
        if "allowed_tools" in entry:
            tool["allowed_tools"] = entry.get("allowed_tools")
        if "headers" in entry:
            tool["headers"] = entry.get("headers")
        tools.append(tool)
    return tools


__all__ = ["build_turn_context", "map_completions_to_responses", "build_mcp_tools"]

# === pipe.py ===
"""Open WebUI pipe entrypoint for the OpenAI Responses manifold."""

import inspect
import logging
from typing import Any, Iterable

# [build.py] internal imports removed in monolith:
# from openai_responses_manifold.core.config import PipeValves, UserValves, merge_valves
# from openai_responses_manifold.core.logging import logging_context
# from openai_responses_manifold.domain import (
#     ResponsesEngine,
#     ToolPolicy,
#     build_code_interpreter_tools,
#     build_web_search_tools,
# )
# from openai_responses_manifold.domain.history import HistoryManager
# from openai_responses_manifold.openai_api import OpenAIClient
# from openai_responses_manifold.openwebui import (
#     OpenWebUIHistoryStore,
#     OpenWebUIRuntimeEvents,
#     OpenWebUIToolExecutor,
#     OpenWebUIToolRegistry,
#     build_mcp_tools,
#     build_turn_context,
#     map_completions_to_responses,
# )


class Pipe:
    """Open WebUI pipe implementation for the Responses manifold."""

    id = "openai_responses"

    class Valves(PipeValves):
        pass

    class UserValves(UserValves):
        pass

    def __init__(self) -> None:
        self.valves = self.Valves()
        self.client = OpenAIClient()
        self.history_store = OpenWebUIHistoryStore()
        self.history_manager = HistoryManager(self.history_store)
        self.engine = ResponsesEngine(self.client, self.history_manager)

    @staticmethod
    def _status_unclamp_script() -> str:
        return """
        (() => {
        if (document.getElementById("owui-status-unclamp")) return "ok";
        const style = document.createElement("style");
        style.id = "owui-status-unclamp";
        style.textContent = `
            .status-description .line-clamp-1,
            .status-description .text-base.line-clamp-1,
            .status-description .text-gray-500.text-base.line-clamp-1 {
            display: block !important;
            overflow: visible !important;
            -webkit-line-clamp: unset !important;
            -webkit-box-orient: initial !important;
            white-space: pre-wrap !important;
            word-break: break-word;
            }

            .status-description .text-base::first-line,
            .status-description .text-gray-500.text-base::first-line {
            font-weight: 500 !important;
            }
        `;

        document.head.appendChild(style);
        return "ok";
        })();
        """

    async def _maybe_unclamp_status(self, event_call: Any | None) -> None:
        if not event_call:
            return
        payload = {"type": "execute", "data": {"code": self._status_unclamp_script()}}
        try:
            result = event_call(payload)
            if inspect.isawaitable(result):
                await result
        except Exception:
            return

    async def pipes(self) -> list[dict[str, Any]]:
        cfg = self.valves
        ids = [m.strip() for m in (cfg.MODEL_ID or "").split(",") if m.strip()]
        return [{"id": model_id, "name": f"OpenAI Responses: {model_id}"} for model_id in ids]

    async def _resolve_tools(self, __tools__: Any) -> Any:
        if inspect.isawaitable(__tools__):
            return await __tools__
        return __tools__

    def _prompt_cache_key(self, cfg: RuntimeConfig, ctx: TurnContext) -> str | None:
        if cfg.PROMPT_CACHE_KEY == "email":
            return ctx.metadata.get("user_email")
        return ctx.metadata.get("user_id")

    def _build_tools_for_request(
        self,
        *,
        request: dict[str, Any],
        ctx: TurnContext,
        cfg: RuntimeConfig,
        registry: OpenWebUIToolRegistry,
        base_tools: list[dict],
        extra_tools: list[dict],
    ) -> None:
        reasoning_effort = (request.get("reasoning") or {}).get("effort")
        web_search_tools = build_web_search_tools(cfg, reasoning_effort=reasoning_effort)
        code_interpreter_tools = build_code_interpreter_tools(cfg)
        tools_for_responses = ToolPolicy.build_responses_tools(
            model_id=ctx.model_id,
            cfg=cfg,
            registry=registry,
            body_tools=base_tools,
            extra_tools=extra_tools,
            mcp_tools=build_mcp_tools(cfg),
            web_search_tools=[*web_search_tools, *code_interpreter_tools],
        )
        if tools_for_responses:
            request["tools"] = tools_for_responses

    def _apply_request_config(self, request: dict[str, Any], cfg: RuntimeConfig, ctx: TurnContext) -> None:
        request["prompt_cache_key"] = self._prompt_cache_key(cfg, ctx)
        request["parallel_tool_calls"] = cfg.PARALLEL_TOOL_CALLS

        # All supported models are reasoning models.
        reasoning = dict(request.get("reasoning") or {})
        if cfg.REASONING_SUMMARY != "disabled":
            reasoning["summary"] = cfg.REASONING_SUMMARY
        if cfg.REASONING_EFFORT:
            reasoning["effort"] = cfg.REASONING_EFFORT
        if reasoning:
            request["reasoning"] = reasoning

        if cfg.PERSIST_REASONING_TOKENS != "disabled":
            include = list(request.get("include") or [])
            if "reasoning.encrypted_content" not in include:
                include.append("reasoning.encrypted_content")
            request["include"] = include

        if cfg.WEB_SEARCH_INCLUDE_SOURCES and any(
            t.get("type") == "web_search" for t in (request.get("tools") or [])
        ):
            include = list(request.get("include") or [])
            if "web_search_call.action.sources" not in include:
                include.append("web_search_call.action.sources")
            request["include"] = include

    async def _persist_result_citations(
        self,
        result: TurnResult,
        metadata: dict[str, Any] | None,
    ) -> None:
        metadata = metadata or {}
        chat_id = metadata.get("chat_id")
        message_id = metadata.get("message_id")
        if not result.citations or not chat_id or not message_id:
            return
        try:
            from open_webui.models.chats import Chats

            Chats.upsert_message_to_chat_by_id_and_message_id(
                chat_id,
                message_id,
                {
                    "sources": [
                        {
                            "source": {"name": c.source_name, "url": c.url},
                            "document": c.document,
                            "metadata": [c.metadata],
                        }
                        for c in result.citations
                    ]
                },
            )
        except Exception:
            get_logger(__name__).debug("Failed to persist citations to Open WebUI chat", exc_info=True)

    async def _emit_turn_diagnostics(
        self,
        *,
        events: "OpenWebUIRuntimeEvents",
        metadata: dict[str, Any] | None,
        session_id: str | None,
        phase: str,
        exc: BaseException | None = None,
    ) -> None:
        """Defensively persist our own turn outcome, independent of OWUI's middleware.

        Open WebUI's tool-calling loop (utils/middleware.py) reinvokes this pipe
        once per tool round and can silently `break` out of that loop on an
        exception logged only at DEBUG level, leaving the assistant message
        untouched (no error, no done=True) if a later step never runs. `status`
        and `citation`/`source` events are persisted to the chat message
        synchronously by Open WebUI's event emitter, independent of whatever the
        middleware does afterwards -- so emitting them here, directly from the
        pipe, guarantees a durable trace of what actually happened on our side
        even if Open WebUI never finalizes the message.
        """
        metadata = metadata or {}
        chat_id = metadata.get("chat_id")
        message_id = metadata.get("message_id")

        if exc is not None:
            self.engine._logger.error(
                "responses-manifold turn failed phase=%s chat_id=%s message_id=%s",
                phase,
                chat_id,
                message_id,
                exc_info=exc,
            )
        else:
            self.engine._logger.info(
                "responses-manifold turn finished phase=%s chat_id=%s message_id=%s",
                phase,
                chat_id,
                message_id,
            )

        if not chat_id or not message_id:
            return

        try:
            if exc is not None:
                await events.status(
                    f"responses-manifold: turn failed ({type(exc).__name__})",
                    done=True,
                )
                tb_text = "".join(
                    traceback.format_exception(type(exc), exc, exc.__traceback__)
                )
                log_lines = consume_session_logs(session_id)
                document_parts = [f"Exception:\n{tb_text}"]
                if log_lines:
                    document_parts.append("Recent manifold logs:\n" + "\n".join(log_lines))
                await events.citation(
                    {
                        "document": document_parts,
                        "metadata": [
                            {
                                "source": "Responses Manifold Error",
                                "phase": phase,
                                "exception_type": type(exc).__name__,
                            }
                        ],
                        "source": {"name": "Responses Manifold Error"},
                    }
                )
            else:
                await events.status(f"responses-manifold: turn completed ({phase})", done=True)
        except Exception:
            self.engine._logger.debug(
                "Failed to emit defensive turn diagnostics", exc_info=True
            )

    async def pipe(
        self,
        body: dict[str, Any] | None = None,
        __user__: dict[str, Any] | None = None,
        __assistant__: dict[str, Any] | None = None,
        __event_emitter__: Any | None = None,
        __event_call__: Any | None = None,
        __tools__: Iterable[Any] | None = None,
        __tasks__: Iterable[Any] | None = None,
        __task__: Any | None = None,
        __task_body__: dict[str, Any] | None = None,
        __metadata__: dict[str, Any] | None = None,
    ) -> Any:
        body = body or {}
        pipe_valves = self.valves
        user_valves = self.UserValves.model_validate((__user__ or {}).get("valves") or {})
        cfg = merge_valves(pipe_valves, user_valves)

        events = OpenWebUIRuntimeEvents(__event_emitter__)
        level = getattr(logging, cfg.LOG_LEVEL.upper(), logging.INFO)

        with logging_context(
            (__metadata__ or {}).get("session_id"),
            level,
            chat_id=(__metadata__ or {}).get("chat_id"),
            message_id=(__metadata__ or {}).get("message_id"),
            user_id=(__user__ or {}).get("id"),
        ):
            await self._maybe_unclamp_status(__event_call__)
            if __task__ is None:
                body = await prepare_context_for_pipe(
                    body,
                    model_id=base_model(str(body.get("model") or cfg.MODEL_ID)),
                    user=__user__,
                    chat_id=(__metadata__ or {}).get("chat_id"),
                    metadata=__metadata__,
                    event_emitter=__event_emitter__,
                )
            ctx = build_turn_context(
                pipe_valves=pipe_valves,
                user_valves=user_valves,
                runtime_cfg=cfg,
                __user__=__user__,
                __metadata__=__metadata__,
                body=body,
            )
            history_key = {"chat_id": (__metadata__ or {}).get("chat_id"), "pipe_id": self.id}
            resolved_tools = await self._resolve_tools(__tools__ or {})
            registry = OpenWebUIToolRegistry(resolved_tools)

            if __task__ is not None:
                request = map_completions_to_responses(
                    body=body, ctx=ctx, history_manager=self.history_manager, history_key=history_key
                )[0]
                request["stream"] = False
                request["store"] = False
                request["tools"] = None
                request["include"] = None
                return await self.engine.run_task(request, ctx)

            if body.get("stream") is False:
                await events.notification("Non-streaming chat is not supported by this manifold.", level="error")
                await events.chat_completion({"done": True, "error": "Streaming required"})
                return ""

            session_id = (__metadata__ or {}).get("session_id")

            try:
                request, base_tools, extra_tools = map_completions_to_responses(
                    body=body, ctx=ctx, history_manager=self.history_manager, history_key=history_key
                )

                self._build_tools_for_request(
                    request=request,
                    ctx=ctx,
                    cfg=cfg,
                    registry=registry,
                    base_tools=base_tools,
                    extra_tools=extra_tools,
                )
                self._apply_request_config(request, cfg, ctx)
            except asyncio.CancelledError:
                raise
            except Exception as exc:
                await self._emit_turn_diagnostics(
                    events=events,
                    metadata=__metadata__,
                    session_id=session_id,
                    phase="request-setup",
                    exc=exc,
                )

                async def _failed_setup() -> AsyncIterator[dict[str, Any]]:
                    yield {
                        "type": "response.failed",
                        "response": {
                            "error": {"type": type(exc).__name__, "message": str(exc)}
                        },
                    }

                return _failed_setup()

            async def _stream_one_response() -> AsyncIterator[dict[str, Any]]:
                try:
                    async for event in self.engine.stream_single_turn(request, ctx):
                        yield event
                except asyncio.CancelledError:
                    raise
                except Exception as exc:
                    self.engine._logger.exception("Responses API stream failed")
                    await self._emit_turn_diagnostics(
                        events=events,
                        metadata=__metadata__,
                        session_id=session_id,
                        phase="stream",
                        exc=exc,
                    )
                    yield {
                        "type": "response.failed",
                        "response": {
                            "error": {
                                "type": type(exc).__name__,
                                "message": str(exc),
                            }
                        },
                    }
                    return
                await self._emit_turn_diagnostics(
                    events=events,
                    metadata=__metadata__,
                    session_id=session_id,
                    phase="stream",
                    exc=None,
                )

            return _stream_one_response()


__all__ = ["Pipe"]

